 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  Alert,
 6	  AlertVariant,
 7	  Button,
 8	  EmptyStateActions,
 9	  EmptyStateBody,
10	  EmptyStateIcon,
11	  Progress,
12	  Stack,
13	  StackItem,
14	  Title,
15	} from '@patternfly/react-core';
16	import { InProgressIcon } from '@patternfly/react-icons';
17	
18	import { UPLOAD_STATUS } from '../../utils/consts';
19	import { UploadingStatusProps } from '../../utils/types';
20	import { getProgressVariant } from '../../utils/utils';
21	
22	const UploadingStatus: FC<UploadingStatusProps> = ({ onCancelClick, onSuccessClick, upload }) => {
23	  const { t } = useKubevirtTranslation();
24	  return (
25	    <>
26	      <EmptyStateIcon icon={InProgressIcon} />
27	      <Title headingLevel="h4" size="lg">
28	        {t('Uploading data to Persistent Volume Claim')}
29	      </Title>
30	      <EmptyStateBody>
31	        <Stack hasGutter>
32	          {upload?.uploadStatus === UPLOAD_STATUS.UPLOADING && (
33	            <StackItem>
34	              <Alert
35	                className="kv--create-upload__alert"
36	                isInline
37	                title={t('Please don’t close this browser tab')}
38	                variant={AlertVariant.warning}
39	              >
40	                {t('Closing it will cause the upload to fail. You may still navigate the console.')}
41	              </Alert>
42	            </StackItem>
43	          )}
44	          <StackItem>
45	            {t(
46	              'Persistent Volume Claim has been created and your data source is now being uploaded to it. Once the uploading is completed the Persistent Volume Claim will become available',
47	            )}
48	          </StackItem>
49	          <StackItem>
50	            <Progress value={upload?.progress} variant={getProgressVariant(upload?.uploadStatus)} />
51	          </StackItem>
52	        </Stack>
53	      </EmptyStateBody>
54	      {onSuccessClick && (
55	        <Button id="cdi-upload-primary-pvc" onClick={onSuccessClick} variant="primary">
56	          {t('View Persistent Volume Claim details')}
57	        </Button>
58	      )}
59	      {onCancelClick && upload?.uploadStatus === UPLOAD_STATUS.UPLOADING && (
60	        <EmptyStateActions>
61	          <Button id="cdi-upload-cancel-btn" onClick={onCancelClick} variant="link">
62	            {t('Cancel Upload')}
63	          </Button>
64	        </EmptyStateActions>
65	      )}
66	    </>
67	  );
68	};
69	
70	export default UploadingStatus;

